async function sbInsert(table, row) {
  const res = await fetch(`${SUPABASE_URL}/rest/v1/${table}`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "apikey": SUPABASE_KEY,
      "Authorization": `Bearer ${SUPABASE_KEY}`,
      "Prefer": "return=minimal",
    },
    body: JSON.stringify(row),
  });
  if (!res.ok) {
    const err = await res.text();
    throw new Error(err);
  }
}

/* ─── shared micro-components ─────────────────────────────────────────────── */
function Field({ label, required, children }) {
  return (
    <div style={{ display:"flex", flexDirection:"column", gap:6, flex:1, minWidth:0 }}>
      <label style={{ fontFamily:"Barlow", fontSize:13, color:MUTED, fontWeight:500 }}>
        {label}{required && <span style={{ color:MINT, marginLeft:3 }}>*</span>}
      </label>
      {children}
    </div>
  );
}

const inputStyle = {
  background: DARK, border:`1px solid ${BORDER}`, borderRadius:6,
  padding:"11px 14px", color:WHITE, fontSize:15, fontFamily:"Barlow",
  outline:"none", width:"100%", boxSizing:"border-box",
};

const selectStyle = { ...inputStyle, cursor:"pointer" };

function Row({ children }) {
  return (
    <div style={{ display:"flex", gap:14, flexWrap:"wrap" }}>
      {children}
    </div>
  );
}

function MintBtn({ children, onClick, disabled, style = {} }) {
  return (
    <button onClick={onClick} disabled={disabled} style={{
      background: disabled ? DIM : MINT,
      color: disabled ? MUTED : BLACK,
      border:"none", borderRadius:7, padding:"14px 32px",
      fontFamily:"Barlow Condensed", fontWeight:800, fontSize:20,
      letterSpacing:1, cursor: disabled ? "not-allowed" : "pointer",
      width:"100%", transition:"background .15s",
      ...style
    }}>{children}</button>
  );
}

function GhostBtn({ children, onClick }) {
  return (
    <button onClick={onClick} style={{
      background:"none", border:`1px solid ${BORDER}`,
      color:MUTED, borderRadius:7, padding:"10px 20px",
      fontFamily:"Barlow Condensed", fontWeight:700, fontSize:16,
      cursor:"pointer", letterSpacing:1,
    }}>{children}</button>
  );
}

/* ─── progress bar ─────────────────────────────────────────────────────────── */
function Progress({ step }) {
  const steps = ["Overview", "Player Info", "Parent Fit"];
  return (
    <div style={{ display:"flex", alignItems:"center", justifyContent:"center", gap:0, marginBottom:32 }}>
      {steps.map((s, i) => {
        const done  = i < step;
        const active = i === step;
        return (
          <div key={s} style={{ display:"flex", alignItems:"center" }}>
            <div style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:5 }}>
              <div style={{
                width:32, height:32, borderRadius:"50%",
                background: done ? MINT : active ? "transparent" : DARK,
                border: `2px solid ${done || active ? MINT : BORDER}`,
                display:"flex", alignItems:"center", justifyContent:"center",
                fontFamily:"Barlow Condensed", fontWeight:800, fontSize:14,
                color: done ? BLACK : active ? MINT : MUTED,
              }}>
                {done ? "✓" : i + 1}
              </div>
              <span style={{
                fontFamily:"Barlow Condensed", fontSize:12, letterSpacing:1,
                color: active ? MINT : done ? MINT2 : MUTED, fontWeight:700,
                whiteSpace:"nowrap",
              }}>{s.toUpperCase()}</span>
            </div>
            {i < steps.length - 1 && (
              <div style={{
                width:60, height:2, margin:"0 6px", marginBottom:18,
                background: done ? MINT : BORDER,
              }} />
            )}
          </div>
        );
      })}
    </div>
  );
}

