/* ══════════════════════════════════════════════════════════════════════════════
   PAGE 2 — PLAYER INFO
══════════════════════════════════════════════════════════════════════════════ */
const EMPTY_PLAYER = {
  parentFirst:"", parentLast:"", phone:"", email:"",
  playerFirst:"", playerLast:"", playerAge:"", dob:"", teamInterest:"",
  school:"", gradYear:"", prevTeam1:"", prevTeam2:"", position:"", position2:"", bio:"",
};

function PlayerPage({ onNext, onBack, data, setData }) {
  const [err, setErr] = useState("");
  const set = k => e => setData(d => ({ ...d, [k]: e.target.value }));

  const validate = () => {
    const req = ["parentFirst","parentLast","phone","email","playerFirst","playerLast","playerAge","dob","teamInterest","position"];
    for (const k of req) {
      if (!data[k].trim()) { setErr("Please fill in all required fields."); return false; }
    }
    if (!/^[^@]+@[^@]+\.[^@]+$/.test(data.email)) { setErr("Please enter a valid email."); return false; }
    return true;
  };

  const handleNext = () => { if (validate()) { setErr(""); onNext(); } };

  return (
    <div style={{ maxWidth:640, margin:"0 auto", padding:"0 16px 60px" }}>
      <Progress step={1} />
      <div style={{ background:PANEL, border:`1px solid ${BORDER}`, borderTop:`3px solid ${MINT}`, borderRadius:10 }}>
        <div style={{ padding:"28px 28px 20px", borderBottom:`1px solid ${BORDER}` }}>
          <p style={{ fontFamily:"Barlow Condensed", fontSize:13, fontWeight:700,
            letterSpacing:4, color:MINT, margin:"0 0 6px", textTransform:"uppercase" }}>Step 1 of 2</p>
          <h2 style={{ fontFamily:"Barlow Condensed", fontWeight:900, fontSize:30, color:WHITE, margin:"0 0 4px" }}>Player Information</h2>
          <p style={{ fontFamily:"Barlow", fontSize:14, color:MUTED, margin:0 }}>Tell us about the player and their experience.</p>
        </div>
        <div style={{ padding:"24px 28px", display:"flex", flexDirection:"column", gap:22 }}>
          <div>
            <p style={{ fontFamily:"Barlow Condensed", fontWeight:700, fontSize:13,
              letterSpacing:3, color:MINT, textTransform:"uppercase",
              margin:"0 0 14px", paddingBottom:8, borderBottom:`1px solid ${BORDER}` }}>Parent / Guardian</p>
            <div style={{ display:"flex", flexDirection:"column", gap:14 }}>
              <Row>
                <Field label="First Name" required><input value={data.parentFirst} onChange={set("parentFirst")} placeholder="First" style={inputStyle} /></Field>
                <Field label="Last Name" required><input value={data.parentLast} onChange={set("parentLast")} placeholder="Last" style={inputStyle} /></Field>
              </Row>
              <Row>
                <Field label="Phone Number" required><input value={data.phone} onChange={set("phone")} placeholder="(817) 555-0000" style={inputStyle} /></Field>
                <Field label="Email Address" required><input type="email" value={data.email} onChange={set("email")} placeholder="you@email.com" style={inputStyle} /></Field>
              </Row>
            </div>
          </div>
          <div>
            <p style={{ fontFamily:"Barlow Condensed", fontWeight:700, fontSize:13,
              letterSpacing:3, color:MINT, textTransform:"uppercase",
              margin:"0 0 14px", paddingBottom:8, borderBottom:`1px solid ${BORDER}` }}>Player</p>
            <div style={{ display:"flex", flexDirection:"column", gap:14 }}>
              <Row>
                <Field label="First Name" required><input value={data.playerFirst} onChange={set("playerFirst")} placeholder="First" style={inputStyle} /></Field>
                <Field label="Last Name" required><input value={data.playerLast} onChange={set("playerLast")} placeholder="Last" style={inputStyle} /></Field>
              </Row>
              <Row>
                <Field label="Age" required><input value={data.playerAge} onChange={set("playerAge")} placeholder="e.g. 11" style={inputStyle} /></Field>
                <Field label="Trying out for" required>
                  <select value={data.teamInterest} onChange={set("teamInterest")} style={selectStyle}>
                    <option value="">Select team</option>
                    {TEAMS.map(t => <option key={t} value={t}>{t} Team</option>)}
                  </select>
                </Field>
              </Row>
              <Field label="Date of Birth" required>
                <input type="date" value={data.dob} onChange={set("dob")} style={inputStyle} />
              </Field>
              <Row>
                <Field label="School"><input value={data.school} onChange={set("school")} placeholder="School name" style={inputStyle} /></Field>
                <Field label="Grad Year"><input value={data.gradYear} onChange={set("gradYear")} placeholder="e.g. 2031" style={inputStyle} /></Field>
              </Row>
              <Field label="Primary Position" required>
                <select value={data.position} onChange={set("position")} style={selectStyle}>
                  <option value="">Select position</option>
                  {POSITIONS.map(p => <option key={p} value={p}>{p}</option>)}
                </select>
              </Field>
              <Field label="Secondary Position (optional)">
                <select value={data.position2} onChange={set("position2")} style={selectStyle}>
                  <option value="">Select position</option>
                  {POSITIONS.map(p => <option key={p} value={p}>{p}</option>)}
                </select>
              </Field>
            </div>
          </div>
          <div>
            <p style={{ fontFamily:"Barlow Condensed", fontWeight:700, fontSize:13,
              letterSpacing:3, color:MINT, textTransform:"uppercase",
              margin:"0 0 14px", paddingBottom:8, borderBottom:`1px solid ${BORDER}` }}>Experience</p>
            <div style={{ display:"flex", flexDirection:"column", gap:14 }}>
              <Field label="Previous Team (most recent)">
                <input value={data.prevTeam1} onChange={set("prevTeam1")} placeholder="Team name or N/A" style={inputStyle} />
              </Field>
              <Field label="Previous Team (before that)">
                <input value={data.prevTeam2} onChange={set("prevTeam2")} placeholder="Team name or N/A" style={inputStyle} />
              </Field>
              <Field label="Anything else we should know about the player?">
                <textarea value={data.bio} onChange={set("bio")} rows={3}
                  placeholder="Injuries, schedule conflicts, other sports, etc."
                  style={{ ...inputStyle, resize:"vertical", minHeight:80 }} />
              </Field>
            </div>
          </div>
          {err && <p style={{ color:RED, fontSize:14, margin:0 }}>{err}</p>}
          <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
            <MintBtn onClick={handleNext}>Continue to Parent Questions</MintBtn>
            <GhostBtn onClick={onBack}>Back to Overview</GhostBtn>
          </div>
        </div>
      </div>
    </div>
  );
}

